@using System.Threading
@inject IProductService ProductService
@implements IDisposable

<div class="product-search">
    <input type="text"
           placeholder="Search products…"
           @oninput="OnSearchInput"
           value="@_query" />

    @if (_isLoading)
    {
        <div class="product-search__status">Searching…</div>
    }
    else if (_error is not null)
    {
        <div class="product-search__status product-search__error">
            Something went wrong. Please try again.
        </div>
    }
    else if (_results is { Count: 0 })
    {
        <div class="product-search__status">No products found.</div>
    }

    @if (_results is { Count: > 0 })
    {
        <div class="product-search__grid">
            @foreach (var product in _results)
            {
                <div class="product-search__card" @onclick="() => SelectProduct(product)">
                    <img class="product-search__card-img"
                         src="@product.ImageUrl"
                         alt="@product.Name" />
                    <div class="product-search__card-body">
                        <h3 class="product-search__card-name">@product.Name</h3>
                        <p class="product-search__card-price">@product.Price.ToString("C")</p>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private string _query = string.Empty;
    private List<Product>? _results;
    private bool _isLoading;
    private Exception? _error;

    private CancellationTokenSource? _debounceCts;
    private CancellationTokenSource? _searchCts;
    private bool _disposed;

    private async Task OnSearchInput(ChangeEventArgs e)
    {
        _query = e.Value?.ToString() ?? string.Empty;

        // Cancel any pending debounce timer.
        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _debounceCts = new CancellationTokenSource();
        var debounceToken = _debounceCts.Token;

        try
        {
            await Task.Delay(300, debounceToken);
        }
        catch (TaskCanceledException)
        {
            return; // User kept typing — wait for the next pause.
        }

        await ExecuteSearchAsync(_query);
    }

    private async Task ExecuteSearchAsync(string query)
    {
        // Cancel any in-flight search so its results are discarded.
        _searchCts?.Cancel();
        _searchCts?.Dispose();
        _searchCts = new CancellationTokenSource();
        var ct = _searchCts.Token;

        if (string.IsNullOrWhiteSpace(query))
        {
            _results = null;
            _error = null;
            _isLoading = false;
            return;
        }

        _isLoading = true;
        _error = null;

        try
        {
            var results = await ProductService.SearchAsync(query, ct);

            // If this search was cancelled while awaiting, discard the results.
            ct.ThrowIfCancellationRequested();

            _results = results;
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // A newer search superseded this one — do nothing.
            return;
        }
        catch (Exception ex)
        {
            _error = ex;
            _results = null;
        }
        finally
        {
            if (!ct.IsCancellationRequested)
            {
                _isLoading = false;
            }
        }
    }

    private async Task SelectProduct(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;

        _debounceCts?.Cancel();
        _debounceCts?.Dispose();
        _searchCts?.Cancel();
        _searchCts?.Dispose();
    }
}

